tests:
def test_register_value():
    c = Container()
    c.register_value('config', {'env': 'prod'})
    assert c.resolve('config') == {'env': 'prod'}

def test_transient_creates_new():
    c = Container()
    counter = {'n': 0}
    def factory(cont):
        counter['n'] += 1
        return counter['n']
    c.register('num', factory, lifetime=Lifetime.TRANSIENT)
    assert c.resolve('num') == 1
    assert c.resolve('num') == 2

def test_singleton_caches():
    c = Container()
    counter = {'n': 0}
    def factory(cont):
        counter['n'] += 1
        return counter['n']
    c.register('num', factory, lifetime=Lifetime.SINGLETON)
    a = c.resolve('num')
    b = c.resolve('num')
    assert a == b == 1

def test_unknown_key_raises():
    c = Container()
    try:
        c.resolve('missing')
        assert False
    except ResolutionError:
        pass

def test_circular_dependency():
    c = Container()
    c.register('a', lambda cont: cont.resolve('b'))
    c.register('b', lambda cont: cont.resolve('a'))
    try:
        c.resolve('a')
        assert False
    except ResolutionError:
        pass
